/**
 * Merge-completion handler.
 *
 * When the in_review poll reports `merged: true` for a task's implementation
 * PR, this handler:
 *
 *   1. Reads the live task state from the feature branch (idempotency guard).
 *   2. Checks out and syncs the feature branch on the management repo.
 *   3. Updates the task YAML: status → done, pr.status → merged, done log entry.
 *   4. Applies the auto-ready rule: scans sibling task YAMLs in the same
 *      feature and transitions todo → ready for any whose depends_on list is
 *      now fully satisfied.
 *   5. Commits all YAML changes (completing task + newly-ready tasks) in one
 *      commit and pushes to the feature branch.  On push rejection, attempts
 *      a fetch+rebase recovery; if the rebase has conflicts, spawns Claude to
 *      resolve the YAML markers.  On persistent failure, emits
 *      pr_merge_done_blocked and skips the workspace PR merge.
 *   6. Merges the management-repo PR (workspace_pr) via the GitHub REST API.
 *      Errors here are non-fatal — the task YAML done state is preserved.
 */

import { execSync, spawnSync, spawn } from "node:child_process";
import { readFileSync, writeFileSync, readdirSync } from "node:fs";
import { join } from "node:path";
import { parse as parseYaml, stringify as yamlStringify } from "yaml";
import type { Task } from "../types/task.js";
import { taskYamlAbsPath, taskYamlRelPath, featuresRoot, TASKS_DIR } from "../paths.js";
import type { PrStatusResult } from "./check-in-review-prs.js";
import { parsePrUrl } from "./check-in-review-prs.js";
import { buildGitCommitEnv } from "../git-env.js";
import { tryReadTaskFromBranch } from "../task-branch-state.js";
import { taskBranchName } from "../paths.js";

// ── Public types ──────────────────────────────────────────────────────────────

export interface HandleMergedPrsOptions {
  /** Results from checkInReviewPrs — only those with merged === true are processed. */
  prResults: PrStatusResult[];
  /** Absolute path to the management (workspace) repo root. */
  workspaceRoot: string;
  /** GitHub owner of the management repo (for workspace PR merge call). */
  mgmtRepoOwner: string;
  /** GitHub repo name of the management repo. */
  mgmtRepoName: string;
  /** GitHub personal access token. */
  githubToken: string;
  /** GIT_AUTHOR_EMAIL for commits and log entries. */
  gitAuthorEmail: string;
  /** GIT_AUTHOR_NAME for commits. Defaults to gitAuthorEmail. */
  gitAuthorName: string;
  /** SSH private key path for git push operations. */
  sshKeyPath?: string;
  /** Structured event emitter for observability. */
  emit: (event: Record<string, unknown>) => void;
  /**
   * Optional override for spawning Claude to resolve YAML conflict markers.
   * Receives the prompt string, the workspace cwd, and the process env.
   * Returns true if resolution succeeded, false otherwise.
   */
  invokeClaudeForResolution?: (
    prompt: string,
    cwd: string,
    env: NodeJS.ProcessEnv,
  ) => Promise<boolean>;
}

// ── Internal helpers ──────────────────────────────────────────────────────────

/**
 * Call the GitHub REST API to merge a pull request.
 * Returns success/failure with full response details on failure.
 */
function mergeWorkspacePrViaApi(
  mgmtRepoOwner: string,
  mgmtRepoName: string,
  prNumber: number,
  githubToken: string,
): { success: boolean; details: string } {
  const url = `https://api.github.com/repos/${mgmtRepoOwner}/${mgmtRepoName}/pulls/${prNumber}/merge`;
  const body = JSON.stringify({ merge_method: "merge" });

  const result = spawnSync(
    "curl",
    [
      "-s", "-X", "PUT",
      "-H", `Authorization: token ${githubToken}`,
      "-H", "Accept: application/vnd.github+json",
      "-H", "Content-Type: application/json",
      "-d", body,
      url,
    ],
    { encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
  );

  if (result.error) {
    return { success: false, details: String(result.error) };
  }
  const stdout = result.stdout ?? "";
  if (!stdout.trim()) {
    return { success: false, details: `curl returned empty response. stderr: ${result.stderr ?? ""}` };
  }

  try {
    const data = JSON.parse(stdout) as { merged?: boolean; message?: string };
    if (data.merged === true) {
      return { success: true, details: "" };
    }
    return { success: false, details: JSON.stringify(data) };
  } catch {
    return { success: false, details: `Non-JSON response: ${stdout}` };
  }
}

/**
 * Return files that currently have conflict markers via `git diff --name-only --diff-filter=U`.
 */
function listConflictedFiles(
  repoRoot: string,
  env: NodeJS.ProcessEnv,
): string[] {
  try {
    const output = execSync(
      `git -C "${repoRoot}" diff --name-only --diff-filter=U`,
      { env, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
    ).trim();
    return output ? output.split("\n") : [];
  } catch {
    return [];
  }
}

/**
 * Build a Claude prompt for resolving YAML task file conflict markers.
 * Instructs Claude to keep the local done/ready status and merge log arrays.
 */
function buildYamlConflictResolutionPrompt(
  repoRoot: string,
  conflictedFiles: string[],
): string {
  const fileList = conflictedFiles.map((f) => `- ${f}`).join("\n");
  return (
    `You are resolving git merge conflicts in YAML task files in the repository at ${repoRoot}.\n` +
    `The following files contain conflict markers (<<<<<<<, =======, >>>>>>>):\n\n` +
    fileList +
    `\n\nFor each file:\n` +
    `1. Read the file contents (which include conflict markers).\n` +
    `2. Resolve the conflict markers using these rules:\n` +
    `   - Keep the LOCAL (<<<<<<< HEAD) values for status, pr.status, execution fields.\n` +
    `   - Merge the log arrays from BOTH sides — include all entries from both HEAD and the incoming branch, sorted by the "at" timestamp.\n` +
    `   - For all other scalar fields, keep the LOCAL value.\n` +
    `3. Write the fully resolved YAML content back to disk.\n\n` +
    `IMPORTANT:\n` +
    `- Do NOT run git add or git commit — only write the resolved file contents.\n` +
    `- Do NOT modify any files that are not listed above.\n` +
    `- After writing all files, respond with a brief summary of what was resolved.`
  );
}

/**
 * Default implementation: spawns Claude CLI to resolve YAML conflict markers.
 */
async function defaultInvokeClaudeForResolution(
  prompt: string,
  cwd: string,
  env: NodeJS.ProcessEnv,
): Promise<boolean> {
  return new Promise((resolve) => {
    const child = spawn(
      "claude",
      [
        "-p", prompt,
        "--max-turns", "5",
        "--output-format", "stream-json",
        "--verbose",
        "--dangerously-skip-permissions",
      ],
      { cwd, env, stdio: ["ignore", "pipe", "pipe"] },
    );

    child.stdout.pipe(process.stdout);
    child.stderr.pipe(process.stderr);

    child.on("close", (code) => resolve(code === 0));
    child.on("error", () => resolve(false));
  });
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Iterate poll results where `merged === true` and close out each task:
 * mark done, activate unblocked dependents, and merge the workspace PR.
 */
export async function handleMergedPrs(opts: HandleMergedPrsOptions): Promise<void> {
  const {
    prResults,
    workspaceRoot,
    mgmtRepoOwner,
    mgmtRepoName,
    githubToken,
    gitAuthorEmail,
    gitAuthorName,
    sshKeyPath,
    emit,
  } = opts;

  const mergedResults = prResults.filter((r) => r.merged === true);
  if (mergedResults.length === 0) return;

  const env = buildGitCommitEnv(gitAuthorEmail, gitAuthorName, sshKeyPath);
  const invoker = opts.invokeClaudeForResolution ?? defaultInvokeClaudeForResolution;

  for (const result of mergedResults) {
    const { taskId, featureId } = result;
    const taskBranch = taskBranchName(featureId, taskId);
    const relPath = taskYamlRelPath(featureId, taskId);

    // ── 1. Idempotency guard: read live task state from feature branch ─────────
    const liveTask = tryReadTaskFromBranch(workspaceRoot, taskBranch, relPath);
    if (!liveTask) {
      emit({
        type: "pr_merge_skip",
        task_id: taskId,
        feature_id: featureId,
        reason: "task_branch_not_found",
      });
      continue;
    }

    if (liveTask.status !== "in_review") {
      emit({
        type: "pr_merge_skip",
        task_id: taskId,
        feature_id: featureId,
        reason: `task_already_${liveTask.status}`,
      });
      continue;
    }

    // ── 2. Checkout and sync feature branch ───────────────────────────────────
    try {
      execSync(`git -C "${workspaceRoot}" fetch origin`, { env, stdio: "pipe" });
      execSync(`git -C "${workspaceRoot}" checkout "${taskBranch}"`, { env, stdio: "pipe" });
      execSync(`git -C "${workspaceRoot}" pull origin "${taskBranch}"`, { env, stdio: "pipe" });
    } catch (e) {
      emit({
        type: "pr_merge_done_blocked",
        task_id: taskId,
        feature_id: featureId,
        reason: "branch_sync_failed",
        details: String(e),
      });
      continue;
    }

    // ── 3. Update task YAML on disk ───────────────────────────────────────────
    const now = new Date().toISOString();
    let task: Task;
    try {
      task = parseYaml(
        readFileSync(taskYamlAbsPath(workspaceRoot, featureId, taskId), "utf-8"),
      ) as Task;
    } catch (e) {
      emit({
        type: "pr_merge_done_blocked",
        task_id: taskId,
        feature_id: featureId,
        reason: "task_yaml_read_failed",
        details: String(e),
      });
      continue;
    }

    // Second idempotency check after checkout (guards against races).
    if (task.status !== "in_review") {
      emit({
        type: "pr_merge_skip",
        task_id: taskId,
        feature_id: featureId,
        reason: `task_already_${task.status}_after_checkout`,
      });
      continue;
    }

    task.status = "done";
    task.pr = { ...task.pr, status: "merged" };
    task.execution.last_updated_by = gitAuthorEmail;
    task.execution.last_updated_at = now;
    task.log.push({
      action: "done",
      by: gitAuthorEmail,
      at: now,
      note: "Implementation PR merged — automated close-out by pr-merge loop.",
    });

    writeFileSync(
      taskYamlAbsPath(workspaceRoot, featureId, taskId),
      yamlStringify(task),
      "utf-8",
    );

    // ── 4. Auto-ready rule: activate sibling tasks whose deps are now satisfied
    const allRelPaths: string[] = [relPath];
    const tasksDir = join(featuresRoot(workspaceRoot), featureId, TASKS_DIR);

    let siblingFiles: string[] = [];
    try {
      siblingFiles = readdirSync(tasksDir).filter(
        (f) => /^T\d+\.yaml$/.test(f) && f !== `${taskId}.yaml`,
      );
    } catch { /* best-effort — skip auto-ready if tasks dir unreadable */ }

    // Build a status map for dependency resolution.
    // Start with the just-completed task (now done).
    const taskStatusMap = new Map<string, string>([[taskId, "done"]]);
    for (const sibFile of siblingFiles) {
      try {
        const sibTask = parseYaml(
          readFileSync(join(tasksDir, sibFile), "utf-8"),
        ) as Task;
        taskStatusMap.set(sibTask.id, sibTask.status);
      } catch { /* skip unreadable files */ }
    }

    for (const sibFile of siblingFiles) {
      try {
        const sibPath = join(tasksDir, sibFile);
        const sibTask = parseYaml(readFileSync(sibPath, "utf-8")) as Task;

        // Only consider todo tasks that depend on the just-completed task.
        if (sibTask.status !== "todo") continue;
        if (!Array.isArray(sibTask.depends_on) || !sibTask.depends_on.includes(taskId)) continue;

        // All deps must now be done.
        const allDepsDone = sibTask.depends_on.every(
          (depId) => taskStatusMap.get(depId) === "done",
        );
        if (!allDepsDone) continue;

        const sibNow = new Date().toISOString();
        sibTask.status = "ready";
        sibTask.log.push({
          action: "ready",
          by: gitAuthorEmail,
          at: sibNow,
          note: `Task activated — dependency ${taskId} merged and marked done.`,
        });

        writeFileSync(sibPath, yamlStringify(sibTask), "utf-8");
        allRelPaths.push(taskYamlRelPath(featureId, sibTask.id));

        emit({
          type: "task_auto_readied",
          task_id: sibTask.id,
          feature_id: featureId,
          activated_by: taskId,
        });
      } catch { /* skip individual sibling errors */ }
    }

    // ── 5. Commit + push with rebase-and-resolve on rejection ─────────────────
    let pushSucceeded = false;

    try {
      for (const rp of allRelPaths) {
        execSync(`git -C "${workspaceRoot}" add "${rp}"`, { env, stdio: "pipe" });
      }
      execSync(
        `git -C "${workspaceRoot}" commit -m "chore(${taskId}): mark done + activate unblocked tasks"`,
        { env, stdio: "pipe" },
      );
    } catch (e) {
      emit({
        type: "pr_merge_done_blocked",
        task_id: taskId,
        feature_id: featureId,
        reason: "commit_failed",
        details: String(e),
      });
      continue;
    }

    const firstPush = spawnSync(
      "git",
      ["-C", workspaceRoot, "push", "origin", taskBranch],
      { env, encoding: "utf-8" },
    );

    if (firstPush.status === 0) {
      pushSucceeded = true;
    } else {
      // Push rejected — attempt fetch + rebase recovery.
      try {
        execSync(`git -C "${workspaceRoot}" fetch origin`, { env, stdio: "pipe" });
      } catch (e) {
        emit({
          type: "pr_merge_done_blocked",
          task_id: taskId,
          feature_id: featureId,
          reason: "fetch_failed_during_push_recovery",
          details: String(e),
        });
        continue;
      }

      const rebaseResult = spawnSync(
        "git",
        ["-C", workspaceRoot, "rebase", `origin/${taskBranch}`],
        { env, encoding: "utf-8" },
      );

      if (rebaseResult.status === 0) {
        // Clean rebase — retry push.
        const retryPush = spawnSync(
          "git",
          ["-C", workspaceRoot, "push", "origin", taskBranch],
          { env, encoding: "utf-8" },
        );
        if (retryPush.status === 0) {
          pushSucceeded = true;
        } else {
          emit({
            type: "pr_merge_done_blocked",
            task_id: taskId,
            feature_id: featureId,
            reason: "push_rejected_after_clean_rebase",
            details: retryPush.stderr ?? "",
          });
          continue;
        }
      } else {
        // Conflicted rebase — spawn Claude to resolve YAML conflict markers.
        const conflictedFiles = listConflictedFiles(workspaceRoot, env);
        const prompt = buildYamlConflictResolutionPrompt(workspaceRoot, conflictedFiles);

        let resolveSucceeded = false;
        try {
          resolveSucceeded = await invoker(prompt, workspaceRoot, env);
        } catch { /* fall through to block */ }

        if (resolveSucceeded) {
          execSync(`git -C "${workspaceRoot}" add -A`, { env, stdio: "pipe" });
          const continueResult = spawnSync(
            "git",
            ["-C", workspaceRoot, "rebase", "--continue"],
            { env: { ...env, GIT_EDITOR: "true", GIT_SEQUENCE_EDITOR: "true" }, encoding: "utf-8" },
          );

          if (continueResult.status === 0) {
            const finalPush = spawnSync(
              "git",
              ["-C", workspaceRoot, "push", "origin", taskBranch],
              { env, encoding: "utf-8" },
            );
            if (finalPush.status === 0) {
              pushSucceeded = true;
            } else {
              spawnSync("git", ["-C", workspaceRoot, "rebase", "--abort"], { env, encoding: "utf-8" });
              emit({
                type: "pr_merge_done_blocked",
                task_id: taskId,
                feature_id: featureId,
                reason: "push_rejected_after_claude_rebase",
                details: finalPush.stderr ?? "",
              });
              continue;
            }
          } else {
            spawnSync("git", ["-C", workspaceRoot, "rebase", "--abort"], { env, encoding: "utf-8" });
            emit({
              type: "pr_merge_done_blocked",
              task_id: taskId,
              feature_id: featureId,
              reason: "rebase_continue_failed_after_claude_resolve",
              details: continueResult.stderr ?? "",
            });
            continue;
          }
        } else {
          spawnSync("git", ["-C", workspaceRoot, "rebase", "--abort"], { env, encoding: "utf-8" });
          emit({
            type: "pr_merge_done_blocked",
            task_id: taskId,
            feature_id: featureId,
            reason: "rebase_conflict_unresolvable",
            conflicted_files: conflictedFiles,
          });
          continue;
        }
      }
    }

    if (!pushSucceeded) continue;

    emit({ type: "task_marked_done", task_id: taskId, feature_id: featureId });

    // ── 6. Merge the workspace PR via GitHub REST API ─────────────────────────
    if (!task.workspace_pr?.url) {
      emit({
        type: "workspace_pr_missing_for_merge",
        task_id: taskId,
        feature_id: featureId,
        note: "workspace_pr is null — skipping workspace PR merge. Task YAML still marked done.",
      });
      continue;
    }

    const coords = parsePrUrl(task.workspace_pr.url);
    if (!coords) {
      emit({
        type: "workspace_pr_merge_failed",
        task_id: taskId,
        feature_id: featureId,
        details: `Cannot parse workspace_pr.url: ${task.workspace_pr.url}`,
      });
      continue;
    }

    const mergeApiResult = mergeWorkspacePrViaApi(
      mgmtRepoOwner,
      mgmtRepoName,
      coords.pullNumber,
      githubToken,
    );

    if (mergeApiResult.success) {
      emit({ type: "workspace_pr_merged", task_id: taskId, feature_id: featureId });
    } else {
      emit({
        type: "workspace_pr_merge_failed",
        task_id: taskId,
        feature_id: featureId,
        details: mergeApiResult.details,
      });
    }
  }
}

